   263→    font-family: var(--font-family);
   264→    font-size: var(--font-size-base);
   265→    font-weight: var(--font-normal);
   266→    line-height: var(--leading-normal);
   267→    color: var(--color-fg);
   268→    background-color: var(--color-bg);
   269→  }
   270→
   271→  /* Headings -- tighter line-height, bolder weight, type scale */
   272→  h1 {
   273→    font-size: var(--font-size-3xl);
   274→    font-weight: var(--font-bold);
