use argon2::password_hash::SaltString;
use argon2::{Argon2, PasswordHash, PasswordHasher, PasswordVerifier};

#[derive(Debug, Clone)]
pub struct Password {
    hash: String,
}

#[derive(Debug, thiserror::Error)]
pub enum PasswordError {
    #[error("Password cannot be empty")]
    Empty,
    #[error("Password is too short (minimum {min} characters, got {actual})")]
    TooShort { min: usize, actual: usize },
    #[error("Password is too long (maximum {max} characters, got {actual})")]
    TooLong { max: usize, actual: usize },
    #[error("Failed to hash password")]
    HashError,
}

const MIN_PASSWORD_LENGTH: usize = 8;
const MAX_PASSWORD_LENGTH: usize = 128;

impl Password {
    pub fn parse(input: &str) -> Result<Self, PasswordError> {
        if input.is_empty() {
            return Err(PasswordError::Empty);
        }

        if input.len() < MIN_PASSWORD_LENGTH {
            return Err(PasswordError::TooShort {
                min: MIN_PASSWORD_LENGTH,
                actual: input.len(),
            });
        }

        if input.len() > MAX_PASSWORD_LENGTH {
            return Err(PasswordError::TooLong {
                max: MAX_PASSWORD_LENGTH,
                actual: input.len(),
            });
        }

        let salt = SaltString::generate(&mut rand_core::OsRng);
        let argon2 = Argon2::default();
        let hash = argon2
            .hash_password(input.as_bytes(), &salt)
            .map_err(|_| PasswordError::HashError)?
            .to_string();

        Ok(Self { hash })
    }

    pub fn from_hash(hash: String) -> Self {
        Self { hash }
    }

    pub fn verify(&self, candidate: &str) -> bool {
        let parsed_hash = match PasswordHash::new(&self.hash) {
            Ok(h) => h,
            Err(_) => return false,
        };
        Argon2::default()
            .verify_password(candidate.as_bytes(), &parsed_hash)
            .is_ok()
    }

    pub fn hash(&self) -> &str {
        &self.hash
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn valid_password_is_accepted() {
        let password = Password::parse("secureP@ss1");
        assert!(password.is_ok());
    }

    #[test]
    fn empty_password_is_rejected() {
        let password = Password::parse("");
        assert!(matches!(password, Err(PasswordError::Empty)));
    }

    #[test]
    fn short_password_is_rejected() {
        let password = Password::parse("short");
        assert!(matches!(
            password,
            Err(PasswordError::TooShort { min: 8, .. })
        ));
    }

    #[test]
    fn password_at_minimum_length_is_accepted() {
        let password = Password::parse("12345678");
        assert!(password.is_ok());
    }

    #[test]
    fn long_password_is_rejected() {
        let long_pass = "a".repeat(129);
        let password = Password::parse(&long_pass);
        assert!(matches!(
            password,
            Err(PasswordError::TooLong { max: 128, .. })
        ));
    }

    #[test]
    fn password_verification_succeeds_with_correct_input() {
        let password = Password::parse("correctpassword").unwrap();
        assert!(password.verify("correctpassword"));
    }

    #[test]
    fn password_verification_fails_with_wrong_input() {
        let password = Password::parse("correctpassword").unwrap();
        assert!(!password.verify("wrongpassword"));
    }
}

